mapper.select:
SELECT mr.id, ci.plate_number AS plate, cm.model_name AS model, mr.maintenance_item AS maintenanceItem, mr.cost, mr.maintenance_date AS maintenanceDate, mr.vehicle_id AS vehicleId, mr.status, mr.remarks FROM maintenance_record mr LEFT JOIN car_info ci ON mr.vehicle_id = ci.car_id LEFT JOIN car_models cm ON ci.model_id = cm.model_id
AND ci.plate_number LIKE CONCAT('%', #{query.plate}, '%')
AND mr.status = #{query.status}
AND mr.maintenance_date >= #{query.dateStart}
AND mr.maintenance_date <= #{query.dateEnd}
ORDER BY mr.maintenance_date DESC, mr.create_time DESC
